#include <iostream>#include <set>using namespace std;multiset<int> st;int main(){    int n,q;    cin>>n>>q;    for(int i=1;i<=n;i++)    {        int x;        cin>>x;        st.insert(x);    }    while(q--)    {        int k;        cin>>k;        if(k>0)        {            st.insert(k);        }        else        {            int t=-k;            auto it=st.begin();            for(int i=1;i<t;i++)            {                it++;            }            st.erase(it);        }    }    if(!st.empty())    {        cout<<*st.begin()<<endl;    }    else    {        cout<<0<<endl;    }    return 0;}